solution to 2nd problem 

```
bool check(vector<int>&pref, int len, int k)
{
    int n = pref.size();

    for (int i = 0; i <= n - len; i++)
    {
        int cnt = 0;

        if (i == 0)
        {
            cnt = pref[i + len - 1];
        }
        else
        {
            cnt = pref[i + len - 1] - pref[i - 1];
        }

        if (cnt >= k) return false;
    }

    return true;
}

int solution(vector<int>&a, int k)
{
    int n = a.size();
    vector<int>pref(n, 0);

    pref[0] = a[0];

    for (int i = 1; i < n; i++)
    {
        pref[i] = pref[i - 1] + a[i];
    }

    int lo = 1, hi = n;
    int ans = 0;

    while (lo <= hi)
    {
        int mid = (lo + hi) >> 1;

        if (check(pref, mid, k)) {
            lo = mid + 1;
            ans = mid;
        }
        else {
            hi = mid - 1;
        }
    }

    return ans;
}
